import { FantasyStat } from "../../objects/fantasy-stat";

interface FantasyStatComponentProps{
    fantasyStats : FantasyStat[]    
}

const FantasyStatTable = (fantasyStatsProps : FantasyStatComponentProps) => {      

    return(
        <>                       
        <div className="row">            
            <div>
                <table className="table table-hover table-condensed table-responsive">
                    <thead>
                        <tr>
                            <th>Player</th>                              
                            <th>Pts</th>  
                            <th>Apps</th>
                            <th>Apps Pts (2)</th>
                            <th>Goals (6, 6, 5, 4)</th>
                            <th>Assists (3)</th>
                            <th>GSOs (1)</th>
                            <th>Shots (1)</th>
                            <th>Tackles (1)</th>                            
                        </tr>
                    </thead>
                    <tbody className="table-group-divider">
                        {fantasyStatsProps.fantasyStats.map(f => 
                            <>
                            <tr key={f.id}>
                                <td className="col-3">{f.playerName}</td>                                                                
                                <td className="col-1">{f.totalPoints}</td>   
                                <td className="col-1">{f.apps}</td>
                                <td className="col-1">{f.appsPts} ({f.apps})</td>
                                <td className="col-1">{f.goalPts} ({f.goals})</td>
                                <td className="col-1">{f.assistsPts} ({f.assists})</td>
                                <td className="col-1">{f.gsoPts} ({f.gso})</td>
                                <td className="col-1">{f.shotPts} ({f.shots})</td>
                                <td className="col-1">{f.tacklePts} ({f.tackles})</td>
                                </tr>
                            </>
                        )}
                    </tbody>
                </table>                          
            </div>
        </div>                
        </>
    );
}
export default FantasyStatTable;


